const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');

function read(filePath) {
  return fs.readFileSync(filePath, 'utf8');
}

function write(filePath, content) {
  fs.writeFileSync(filePath, content, 'utf8');
}

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function matchOne(content, regex) {
  const match = content.match(regex);
  return match ? match[1].trim() : '';
}

function applyExactMap(content, replacements) {
  let result = content;
  for (const [from, to] of replacements) {
    result = result.split(from).join(to);
  }
  return result;
}

function applyRegexMap(content, replacements) {
  let result = content;
  for (const [pattern, to] of replacements) {
    result = result.replace(pattern, to);
  }
  return result;
}

function upsertMeta(content, attr, value, anchors = []) {
  const tag = `<meta ${attr} content="${value}">`;
  const metaRegex = new RegExp(`<meta\\s+${escapeRegExp(attr)}\\s+content="[^"]*"\\s*\\/?>`);

  if (metaRegex.test(content)) {
    return content.replace(metaRegex, tag);
  }

  for (const anchor of anchors) {
    if (anchor.test(content)) {
      return content.replace(anchor, `$&\n${tag}`);
    }
  }

  return content.replace(/<\/head>/i, `${tag}\n</head>`);
}

function inferSwLocale(content) {
  const enHref = matchOne(content, /<link rel="alternate" hreflang="en" href="([^"]+)"/);
  const codeMatch = enHref.match(/\/([a-z]{2})-(?:paye|salary-tax)(?:\.html)?\/?$/i);
  return codeMatch ? `sw_${codeMatch[1].toUpperCase()}` : 'sw_KE';
}

function normalizeHeadMeta(content) {
  const canonical = matchOne(content, /<link rel="canonical" href="([^"]+)"\s*\/?>/);
  if (!canonical) return content;

  let result = content;
  result = upsertMeta(result, 'property="og:url"', canonical, [
    /<meta\s+property="og:title"\s+content="[^"]*"\s*\/?>/i,
    /<link rel="canonical" href="[^"]+"\s*\/?>/i,
  ]);
  result = upsertMeta(result, 'property="og:locale"', inferSwLocale(result), [
    /<meta\s+property="og:url"\s+content="[^"]*"\s*\/?>/i,
    /<meta\s+property="og:title"\s+content="[^"]*"\s*\/?>/i,
  ]);
  return result;
}

function collectSwPayeFiles() {
  const files = [];
  const root = path.join(ROOT, 'sw');

  function walk(dir) {
    for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
      const abs = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        walk(abs);
        continue;
      }
      if (
        entry.isFile() &&
        entry.name === 'index.html' &&
        abs.includes(`${path.sep}kikokotoo-kodi-mshahara${path.sep}`)
      ) {
        files.push(abs);
      }
    }
  }

  walk(root);
  return files.sort();
}

